    public static List<String> types() {
        return Collections.unmodifiableList(new ArrayList<>(SCHEMAS.keySet()));
    }

    public static List<FieldInfo> fields(String typeName) {
        List<FieldInfo> fields = SCHEMAS.get(typeName);
        if (fields == null) throw new IllegalArgumentException("unknown msgpack-pjsekai type: " + typeName);
        return fields;
    }

    private static Object get(Map<?, ?> values, Object key) {
        Object direct = values.get(key);
        if (direct != null || values.containsKey(key)) return direct;
        if (key instanceof Number) {
            long target = ((Number)key).longValue();
            for (Map.Entry<?, ?> entry : values.entrySet()) {
                Object actual = entry.getKey();
                if (actual instanceof Number && ((Number)actual).longValue() == target) return entry.getValue();
            }
        }
        return null;
    }

    private static Boolean asBoolean(Object value) {
        return value instanceof Boolean ? (Boolean)value : null;
    }

    private static Long asLong(Object value) {
        return value instanceof Number ? Long.valueOf(((Number)value).longValue()) : null;
    }

    private static Double asDouble(Object value) {
        return value instanceof Number ? Double.valueOf(((Number)value).doubleValue()) : null;
    }

    private static String asString(Object value) {
        return value == null ? null : value.toString();
    }

    private static Object asObject(Object value) {
        return value;
    }

    public static final class BufferMessage {
        public static final List<FieldInfo> SCHEMA = Collections.unmodifiableList(Arrays.asList(
            new FieldInfo("SequenceNo", "int", Long.valueOf(100L)),
            new FieldInfo("TargetTime", "int", Long.valueOf(101L))
        ));

        public Long SequenceNo;
        public Long TargetTime;

        public Map<Object, Object> toMsgpackMap() {
            Map<Object, Object> out = new LinkedHashMap<>();
            if (this.SequenceNo != null) out.put(Long.valueOf(100L), this.SequenceNo);
            if (this.TargetTime != null) out.put(Long.valueOf(101L), this.TargetTime);
            return out;
        }

        public byte[] encode() throws IOException {
            return packNative(toMsgpackMap());
        }

        public BufferMessage decode(byte[] data) throws IOException {
            Object unpacked = unpackNative(data);
            if (!(unpacked instanceof Map)) throw new IOException("expected MessagePack map");
            Map<?, ?> raw = (Map<?, ?>)unpacked;
            Object value;
            value = get(raw, Long.valueOf(100L)); if (value != null) this.SequenceNo = asLong(value);
            value = get(raw, Long.valueOf(101L)); if (value != null) this.TargetTime = asLong(value);
            return this;
        }
    }

